// Service worker bootstrap, generated by lofigui wasm-deploy.
// Edit the library templates if you need different behaviour.
//
// Set DEBUG = true to forward SW console output to the page and patch
// WebAssembly.instantiateStreaming / Go.prototype.run for visible errors.
var DEBUG = false;

var swlog = function() {};
var wasmState;

if (DEBUG) {
  swlog = function(msg) {
    console.log('[sw] ' + msg);
    self.clients.matchAll().then(function(clients) {
      clients.forEach(function(c) { c.postMessage({type: 'swlog', msg: msg}); });
    });
  };

  var origError = console.error;
  console.error = function() {
    origError.apply(console, arguments);
    var msg = Array.prototype.slice.call(arguments).join(' ');
    self.clients.matchAll().then(function(clients) {
      clients.forEach(function(c) { c.postMessage({type: 'swlog', msg: 'STDERR: ' + msg}); });
    });
  };

  wasmState = {status: 'loading', error: null, t0: Date.now()};

  var origInstantiate = WebAssembly.instantiateStreaming;
  WebAssembly.instantiateStreaming = function() {
    return origInstantiate.apply(this, arguments).then(function(result) {
      swlog('WASM compiled successfully');
      return result;
    }, function(err) {
      swlog('WASM compile FAILED: ' + err);
      wasmState.error = err.toString();
      throw err;
    });
  };
}

importScripts('wasm_exec.js');
importScripts('wasmhttp_sw.js');

self.addEventListener('install', function() { self.skipWaiting(); });
self.addEventListener('activate', function(event) {
  event.waitUntil(clients.claim());
});

registerWasmHTTPListener('main.wasm', {
    passthrough: function(request) {
        var url = new URL(request.url);
        if (url.hostname !== self.location.hostname) return true;
        // The bootstrap (index.html) is served by the static host when no
        // SW is active. Pass it through so direct /index.html hits don't
        // fall through to the Go handler (which has no such route).
        if (url.pathname.endsWith('/index.html')) return true;
        if (url.pathname.endsWith("/demo.html")) return true;
        return false;
    }
});
